from typing import Optional

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def deleteMiddle(self, head: Optional[ListNode]) -> Optional[ListNode]:
        if head is None or head.next is None:
            return None

        prev_to_middle = head
        slow = head.next
        fast = head.next.next

        while fast and fast.next:
            prev_to_middle = prev_to_middle.next
            slow = slow.next
            fast = fast.next.next

        prev_to_middle.next = slow.next

        return head
